from flask import Flask, jsonify
from bitcoinlib.networks import Network
from bitcoinlib.services.services import Service
import requests
import json

app = Flask(__name__)

# Initialize Bitcoin network connection
try:
    # Connect to Bitcoin network using bitcoinlib
    network = Network('bitcoin')
    service = Service(network='bitcoin', providers=['bitcoind'])
except Exception as e:
    print(f"Warning: Could not connect to Bitcoin Core RPC: {e}")
    service = None

def get_bitcoin_data(endpoint, params=None):
    """Helper function to make requests to Bitcoin network"""
    try:
        if service:
            return service
        else:
            # Fallback to public API if direct connection fails
            base_url = "https://blockstream.info/api"
            response = requests.get(f"{base_url}/{endpoint}", params=params, timeout=10)
            if response.status_code == 200:
                return response.json()
            else:
                return None
    except Exception as e:
        print(f"Error fetching data: {e}")
        return None

@app.route('/block/<block_hash>', methods=['GET'])
def get_block(block_hash):
    """Get block details by block hash"""
    try:
        # Try to get block data using bitcoinlib service
        if service:
            try:
                block_data = service.getblock(block_hash)
                if block_data:
                    response = {
                        "hash": block_data.get('hash', block_hash),
                        "height": block_data.get('height', 0),
                        "merkleroot": block_data.get('merkleroot', ''),
                        "time": block_data.get('time', 0),
                        "nonce": block_data.get('nonce', 0),
                        "tx": block_data.get('tx', [])
                    }
                    return jsonify(response)
            except Exception as e:
                print(f"Service error: {e}")

        # Fallback to public API
        response = requests.get(f"https://blockstream.info/api/block/{block_hash}", timeout=10)
        if response.status_code == 200:
            data = response.json()
            block_response = {
                "hash": data.get('id', block_hash),
                "height": data.get('height', 0),
                "merkleroot": data.get('merkle_root', ''),
                "time": data.get('timestamp', 0),
                "nonce": data.get('nonce', 0),
                "tx": data.get('tx', [])
            }
            return jsonify(block_response)
        else:
            return jsonify({"error": "Block not found"}), 404

    except Exception as e:
        return jsonify({"error": f"Error fetching block: {str(e)}"}), 500

@app.route('/transaction/<txid>', methods=['GET'])
def get_transaction(txid):
    """Get transaction details by transaction ID"""
    try:
        # Try to get transaction data using bitcoinlib service
        if service:
            try:
                tx_data = service.gettransaction(txid)
                if tx_data:
                    response = {
                        "txid": tx_data.get('txid', txid),
                        "blockhash": tx_data.get('blockhash', ''),
                        "vin": tx_data.get('vin', []),
                        "vout": tx_data.get('vout', [])
                    }
                    return jsonify(response)
            except Exception as e:
                print(f"Service error: {e}")

        # Fallback to public API
        response = requests.get(f"https://blockstream.info/api/tx/{txid}", timeout=10)
        if response.status_code == 200:
            data = response.json()
            tx_response = {
                "txid": data.get('txid', txid),
                "blockhash": data.get('status', {}).get('block_hash', ''),
                "vin": data.get('vin', []),
                "vout": data.get('vout', [])
            }
            return jsonify(tx_response)
        else:
            return jsonify({"error": "Transaction not found"}), 404

    except Exception as e:
        return jsonify({"error": f"Error fetching transaction: {str(e)}"}), 500

@app.route('/status', methods=['GET'])
def get_status():
    """Get network status"""
    try:
        # Check if we can connect to Bitcoin network
        if service:
            try:
                # Try to get latest block to verify connection
                latest_block = service.blockcount()
                if latest_block:
                    return jsonify({"status": "online"})
            except Exception as e:
                print(f"Service status error: {e}")

        # Fallback to check public API
        response = requests.get("https://blockstream.info/api/blocks/tip/height", timeout=10)
        if response.status_code == 200:
            return jsonify({"status": "online"})
        else:
            return jsonify({"status": "error: Unable to connect to Bitcoin network"})

    except Exception as e:
        return jsonify({"status": f"error: {str(e)}"})

@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Endpoint not found"}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({"error": "Internal server error"}), 500

if __name__ == '__main__':
    print("Starting Bitcoin Service API...")
    print("Available endpoints:")
    print("  GET /block/<block_hash> - Get block details")
    print("  GET /transaction/<txid> - Get transaction details")
    print("  GET /status - Get network status")
    print("\nService running on http://localhost:5000")

    # Start Flask app on port 5000
    app.run(host='0.0.0.0', port=5000, debug=False)
